import jwt
from datetime import datetime, timedelta

def generate_jwt(user_id, role):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.utcnow() + timedelta(minutes=30)
    }
    
    secret_key = 'your_secret_key_here'  # Replace with your own secret key
    return jwt.encode(payload, secret_key, algorithm='HS256')

def verify_jwt(token):
    try:
        payload = jwt.decode(token, 'your_secret_key_here', algorithms=['HS256'])
        return payload['user_id'], payload['role']
    except jwt.ExpiredSignatureError:
        print("Token has expired")
        return None
    except jwt.InvalidTokenError:
        print("Invalid token")
        return None

# Example usage:
token = generate_jwt(123, 'admin')
print(token)

user_id, role = verify_jwt(token)
print(user_id, role)